TEMPLATE = '<!DOCTYPE html>\n<html lang="zh-TW">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width,initial-scale=1.0,maximum-scale=1.0,user-scalable=no">\n<title>乾媽智囊團</title>\n<style>\n:root{\n  --br:#6B4226;--brl:#8B5A3A;--brd:#4A2C18;--brbg:#FDF6F0;\n  --cr:#FAF0E6;--gold:#C9A96E;--tx:#2C1810;--txl:#6B4226;\n  --gray:#888;--bor:#E8D5C4;--wh:#fff;\n  --hh:48px;--fh:52px;\n  --cat-c:#8B6914;--cat-bg:#FFF8E1;\n}\nbody.dark{\n  --br:#C9A96E;--brl:#D4B87A;--brd:#E8D5A0;--brbg:#2A2018;\n  --cr:#1A1510;--gold:#C9A96E;--tx:#F0E6D8;--txl:#C9A96E;\n  --gray:#777;--bor:#3A2C1E;--wh:#231A10;\n  --cat-c:#E8C84A;--cat-bg:#2A2010;\n}\n*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\nhtml,body{height:100%;overflow:hidden}\nbody{font-family:\'Helvetica Neue\',\'PingFang TC\',\'Noto Sans TC\',sans-serif;background:var(--cr);color:var(--tx);touch-action:pan-y;transition:background .3s,color .3s}\n\n/* HEADER */\n#hdr{position:fixed;top:0;left:0;right:0;z-index:200;height:var(--hh);background:var(--br);display:flex;align-items:center;justify-content:center;box-shadow:0 2px 8px rgba(0,0,0,.2)}\nbody.dark #hdr{background:#2A1A08}\n#hdr h1{color:var(--gold);font-size:16px;font-weight:700;letter-spacing:.05em}\n#dtog{position:absolute;right:12px;top:50%;transform:translateY(-50%);background:rgba(255,255,255,.12);border:1.5px solid rgba(255,255,255,.25);border-radius:20px;padding:4px 10px;color:var(--gold);font-size:13px;cursor:pointer}\n\n/* FOOTER */\n#ftr{position:fixed;bottom:0;left:0;right:0;z-index:200;height:var(--fh);background:var(--br);display:flex;align-items:center;justify-content:center;gap:7px;padding:0 8px;box-shadow:0 -2px 8px rgba(0,0,0,.2)}\nbody.dark #ftr{background:#2A1A08}\n.np{padding:5px 12px;border-radius:20px;border:1.5px solid var(--gold);color:var(--gold);font-size:13px;font-weight:500;cursor:pointer;white-space:nowrap;transition:all .2s}\n.np.on{background:var(--gold);color:#4A2C18;font-weight:700}\n\n/* PAGES */\n#pgs{position:fixed;top:var(--hh);bottom:var(--fh);left:0;right:0;overflow:hidden}\n.pg{position:absolute;top:0;bottom:0;left:0;right:0;overflow-y:auto;overflow-x:hidden;background:var(--cr);transition:transform .3s cubic-bezier(.4,0,.2,1);-webkit-overflow-scrolling:touch}\n.pg.hl{transform:translateX(-100%)}\n.pg.hr{transform:translateX(100%)}\n.pg.on{transform:translateX(0)}\n\n/* HOME */\n#pg0{padding:16px 14px 20px}\n.hgrid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px}\n.hcard{background:var(--wh);border-radius:14px;border:1.5px solid var(--bor);padding:14px;cursor:pointer;aspect-ratio:1;display:flex;flex-direction:column;position:relative;box-shadow:0 2px 8px rgba(107,66,38,.06);transition:transform .15s}\n.hcard:active{transform:scale(.97)}\n.hcard .hico{font-size:22px}\n.hcard .hlbl{font-size:13px;color:var(--txl);font-weight:600;margin-top:6px}\n.hcard .hnum{position:absolute;left:14px;bottom:12px;font-size:34px;font-weight:900;color:var(--br);line-height:1}\n.hcred{text-align:center;margin-top:4px}\n.cred-pill{display:inline-block;padding:5px 16px;border-radius:20px;border:1.5px solid #ccc;color:#999;font-size:11px}\n\n/* SEARCH */\n.sw{padding:10px 14px 6px;background:var(--cr);position:sticky;top:0;z-index:10;border-bottom:1px solid var(--bor)}\n.sr{position:relative;display:flex;align-items:center}\n.si{width:100%;padding:9px 34px 9px 13px;border-radius:24px;border:1.5px solid var(--bor);background:var(--wh);font-size:14px;color:var(--tx);outline:none;transition:border-color .2s}\n.si:focus{border-color:var(--br)}\n.sc{position:absolute;right:11px;color:var(--gray);font-size:15px;cursor:pointer;padding:4px;display:none;line-height:1}\n.sc.show{display:block}\n\n/* FILTERS */\n.fs{padding:6px 14px 2px}\n.fg{margin-bottom:3px}\n.ftog{display:flex;align-items:center;gap:5px;cursor:pointer;padding:5px 0;font-size:12px;color:var(--br);font-weight:600;user-select:none}\n.ftog .arr{font-size:9px;transition:transform .2s;display:inline-block}\n.ftog.op .arr{transform:rotate(90deg)}\n.fcnt{color:var(--gray);font-weight:400}\n.fal{color:var(--brl);font-size:11px;background:var(--brbg);padding:1px 7px;border-radius:8px}\n.cw{display:flex;flex-wrap:wrap;gap:5px;padding:5px 0 3px}\n.ch{padding:4px 11px;border-radius:16px;border:1.5px solid var(--bor);font-size:12px;color:var(--txl);cursor:pointer;background:var(--wh);transition:all .15s;white-space:nowrap}\n.ch.on{background:var(--br);color:var(--wh);border-color:var(--br)}\n.ch:active{opacity:.7}\n.clr-btn{margin:4px 0 2px;padding:4px 12px;border-radius:14px;border:1.5px solid #e08060;color:#e08060;font-size:11px;font-weight:600;cursor:pointer;background:var(--wh);display:inline-block}\n.clr-btn:active{background:#e08060;color:#fff}\n\n/* LIST */\n.lc{padding:4px 14px 20px}\n.rc{font-size:12px;color:var(--gray);margin-bottom:6px;display:flex;justify-content:space-between;align-items:center}\n.top-btn{font-size:11px;color:var(--br);background:var(--brbg);border:1px solid var(--bor);border-radius:12px;padding:3px 10px;cursor:pointer}\n\n/* ITEM CARDS */\n.ic{background:var(--wh);border-radius:12px;border:1.5px solid var(--bor);margin-bottom:9px;overflow:hidden;box-shadow:0 1px 4px rgba(107,66,38,.05)}\n.ih{padding:11px 13px 9px;cursor:pointer;display:flex;justify-content:space-between;align-items:flex-start;gap:8px}\n.ih:active{background:rgba(107,66,38,.03)}\n.in{font-size:15px;font-weight:700;color:var(--tx);line-height:1.3;flex:1}\n.im{font-size:11px;color:var(--gray);margin-top:3px;display:flex;gap:4px;flex-wrap:wrap;align-items:center}\n.mcat{color:var(--cat-c);font-weight:600;background:var(--cat-bg);padding:1px 7px;border-radius:8px;font-size:11px}\n.mref{font-size:11px;color:var(--txl)}\n.ieb{color:var(--br);font-size:13px;flex-shrink:0;padding-top:2px}\n\n.itags{display:flex;flex-wrap:wrap;gap:4px;padding:0 13px 9px}\n.tb{padding:2px 8px;border-radius:10px;background:var(--brbg);color:var(--br);font-size:11px;font-weight:600}\n\n.idet{border-top:1px solid var(--bor);padding:11px 13px;display:none}\n.idet.op{display:block}\n.rev{font-size:13px;color:var(--tx);line-height:1.6;white-space:pre-wrap;margin-bottom:10px}\n.lnks{display:flex;flex-wrap:wrap;gap:7px;margin-bottom:8px}\n.lnk{padding:5px 12px;border-radius:16px;font-size:12px;font-weight:600;text-decoration:none;display:inline-block;transition:all .15s;border:1.5px solid}\n.lnk-g{border-color:#D32F2F;color:#D32F2F}\n.lnk-g:active{background:#D32F2F;color:#fff}\n.lnk-f{border-color:#1877F2;color:#1877F2}\n.lnk-f:active{background:#1877F2;color:#fff}\n.lnk-i{border-color:#E4621B;color:#E4621B}\n.lnk-i:active{background:#E4621B;color:#fff}\n.lnk-w{border-color:#888;color:#888}\n.lnk-w:active{background:#888;color:#fff}\n\n/* RELATED QUESTIONS */\n.rq-sec{margin-top:8px;border-top:1px dashed var(--bor);padding-top:8px}\n.rq-title{font-size:12px;font-weight:700;color:var(--br);margin-bottom:6px}\n.rq-item{font-size:12px;color:var(--txl);padding:4px 0;cursor:pointer;border-bottom:1px solid rgba(107,66,38,.06);display:flex;gap:6px;align-items:flex-start;line-height:1.4}\n.rq-item:last-child{border-bottom:none}\n.rq-item:active{color:var(--br)}\n.rq-sq{width:6px;height:6px;background:var(--br);border-radius:1px;flex-shrink:0;margin-top:4px}\n\n/* NEARBY */\n.nb-sec{margin-top:10px;border-top:1px dashed var(--bor);padding-top:8px}\n.nb-title{font-size:12px;font-weight:700;color:var(--br);margin-bottom:6px}\n.nb-gtitle{font-size:11px;color:var(--gray);margin:5px 0 3px;font-weight:600}\n.nb-item{font-size:12px;color:var(--txl);padding:4px 0;cursor:pointer;border-bottom:1px solid rgba(107,66,38,.05);display:flex;gap:5px;align-items:center}\n.nb-item:last-child{border-bottom:none}\n.nb-item:active{color:var(--br)}\n.nb-more{font-size:11px;color:var(--br);padding:4px 0;cursor:pointer;font-weight:600}\n.nb-extra{display:none}\n.nb-extra.op{display:block}\n.nb-none{font-size:12px;color:var(--gray);font-style:italic;padding:2px 0}\n\n/* Q CARDS */\n.qc{background:var(--wh);border-radius:12px;border:1.5px solid var(--bor);margin-bottom:8px;padding:11px 13px;box-shadow:0 1px 4px rgba(107,66,38,.05)}\n.qc.hot{border-color:#ff4444;border-width:2px}\n.qt{font-size:14px;font-weight:600;color:var(--tx);line-height:1.4;display:flex;align-items:flex-start;gap:7px}\n.qsq{width:8px;height:8px;background:var(--br);border-radius:2px;flex-shrink:0;margin-top:4px}\n.qfire{font-size:14px;flex-shrink:0}\n.qr2{display:flex;gap:8px;align-items:center;margin-top:4px;padding-left:15px;flex-wrap:wrap}\n.qdate{font-size:11px;color:var(--gray)}\n.qhot-badge{font-size:11px;padding:2px 8px;border-radius:10px;border:1.5px solid #ff4444;color:#ff4444;font-weight:600}\n.qcnts{display:flex;gap:5px;flex-wrap:wrap}\n.qcb{font-size:10px;padding:2px 7px;border-radius:8px;font-weight:600}\n.qcf{background:#FFF0E6;color:#C06020}\n.qch{background:#E6F0FF;color:#2060C0}\n.qcs{background:#E6FFE6;color:#206020}\n.qtags{display:flex;flex-wrap:wrap;gap:4px;margin-top:5px;padding-left:15px}\n.qtag{padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600}\n/* Region colors */\n.qtag-n{background:#E8F4FF;color:#1565C0}\n.qtag-w{background:#E8F5E9;color:#2E7D32}\n.qtag-s{background:#FFF3E0;color:#E65100}\n.qtag-e{background:#F3E5F5;color:#6A1B9A}\n.qtag-i{background:#FCE4EC;color:#AD1457}\n.qtag-t{background:var(--brbg);color:var(--br)}\n\n.empty{text-align:center;padding:40px 20px;color:var(--gray);font-size:14px}\n</style>\n</head>\n<body>\n\n<script id="dbdata" type="application/json">__DATA__</script>\n\n<div id="hdr">\n  <h1>乾媽智囊團</h1>\n  <button id="dtog" onclick="toggleDark()">🌙</button>\n</div>\n\n<div id="pgs">\n\n  <!-- HOME -->\n  <div class="pg on" id="pg0">\n    <div id="hgrid" style="display:grid;grid-template-columns:1fr 1fr;gap:12px;padding:16px 14px;"></div>\n    <div class="hcred" style="padding:0 14px 20px"><span class="cred-pill">BY 新北三重-Alice wang1️⃣🌰</span></div>\n  </div>\n\n  <!-- 問題 -->\n  <div class="pg hr" id="pg1">\n    <div class="sw">\n      <div class="sr">\n        <input class="si" id="si-q" placeholder="搜尋問題..." oninput="onSI(\'q\')">\n        <span class="sc" id="sc-q" onclick="clearSI(\'q\')">✕</span>\n      </div>\n    </div>\n    <div class="fs" id="fs-q"></div>\n    <div class="lc">\n      <div class="rc" id="rc-q"></div>\n      <div id="ql"></div>\n      <div style="text-align:center;padding:12px 0 4px">\n        <span class="top-btn" onclick="backTop(\'pg1\')">⬆ 回到頂端</span>\n      </div>\n    </div>\n  </div>\n\n  <!-- 美食 -->\n  <div class="pg hr" id="pg2">\n    <div class="sw">\n      <div class="sr">\n        <input class="si" id="si-f" placeholder="搜尋美食..." oninput="onSI(\'f\')">\n        <span class="sc" id="sc-f" onclick="clearSI(\'f\')">✕</span>\n      </div>\n    </div>\n    <div class="fs" id="fs-f"></div>\n    <div class="lc">\n      <div class="rc" id="rc-f"></div>\n      <div id="fl"></div>\n      <div style="text-align:center;padding:12px 0 4px">\n        <span class="top-btn" onclick="backTop(\'pg2\')">⬆ 回到頂端</span>\n      </div>\n    </div>\n  </div>\n\n  <!-- 住宿 -->\n  <div class="pg hr" id="pg3">\n    <div class="sw">\n      <div class="sr">\n        <input class="si" id="si-h" placeholder="搜尋住宿..." oninput="onSI(\'h\')">\n        <span class="sc" id="sc-h" onclick="clearSI(\'h\')">✕</span>\n      </div>\n    </div>\n    <div class="fs" id="fs-h"></div>\n    <div class="lc">\n      <div class="rc" id="rc-h"></div>\n      <div id="hl"></div>\n      <div style="text-align:center;padding:12px 0 4px">\n        <span class="top-btn" onclick="backTop(\'pg3\')">⬆ 回到頂端</span>\n      </div>\n    </div>\n  </div>\n\n  <!-- 景點 -->\n  <div class="pg hr" id="pg4">\n    <div class="sw">\n      <div class="sr">\n        <input class="si" id="si-s" placeholder="搜尋景點..." oninput="onSI(\'s\')">\n        <span class="sc" id="sc-s" onclick="clearSI(\'s\')">✕</span>\n      </div>\n    </div>\n    <div class="fs" id="fs-s"></div>\n    <div class="lc">\n      <div class="rc" id="rc-s"></div>\n      <div id="sl"></div>\n      <div style="text-align:center;padding:12px 0 4px">\n        <span class="top-btn" onclick="backTop(\'pg4\')">⬆ 回到頂端</span>\n      </div>\n    </div>\n  </div>\n\n</div>\n\n<div id="ftr">\n  <div class="np on" data-p="0" onclick="goPage(0)">首頁</div>\n  <div class="np" data-p="1" onclick="goPage(1)">問題</div>\n  <div class="np" data-p="2" onclick="goPage(2)">美食</div>\n  <div class="np" data-p="3" onclick="goPage(3)">住宿</div>\n  <div class="np" data-p="4" onclick="goPage(4)">景點</div>\n</div>\n\n<script>\n// ===== DATA =====\nconst DB = JSON.parse(document.getElementById(\'dbdata\').textContent);\nconst Q=DB.q, F=DB.f, H=DB.h, S=DB.s;\n\n// ===== CONSTANTS =====\nconst REGION_ORDER = [\'北部\',\'西部\',\'南部\',\'東部\',\'離島\'];\nconst REGIONS = {\n  \'北部\':[\'基隆\',\'台北\',\'臺北\',\'新北\',\'桃園\',\'新竹\',\'宜蘭\'],\n  \'西部\':[\'苗栗\',\'台中\',\'臺中\',\'彰化\',\'南投\'],\n  \'南部\':[\'雲林\',\'嘉義\',\'台南\',\'臺南\',\'高雄\',\'屏東\',\'澎湖\'],\n  \'東部\':[\'花蓮\',\'台東\'],\n  \'離島\':[\'金門\',\'馬祖\'],\n};\n// Normalize city names\nconst CITY_NORM={\'臺北\':\'台北\',\'臺中\':\'台中\',\'臺南\':\'台南\'};\nfunction nc(c){return c?(CITY_NORM[c]||c):c}\n\nconst CITY_REGION={};\nObject.entries(REGIONS).forEach(([r,cs])=>cs.forEach(c=>{CITY_REGION[nc(c)]=r}));\nconst REGION_TAG_CLASS={\'北部\':\'n\',\'西部\':\'w\',\'南部\':\'s\',\'東部\':\'e\',\'離島\':\'i\'};\n\nconst CITY_ORDER=[];\nREGION_ORDER.forEach(r=>REGIONS[r].forEach(c=>{const n=nc(c);if(!CITY_ORDER.includes(n))CITY_ORDER.push(n)}));\n\nconst LOC_TAGS=new Set([...Object.values(REGIONS).flat().map(nc),\'出國\',\'日本\',\'韓國\',\'泰國\',\'歐洲\',\'港澳\']);\nconst TOPIC_PRI=[\'美食\',\'住宿\',\'旅遊\'];\n\nconst CAT={\n  \'A.小吃\':\'小吃\',\'B.餐廳\':\'餐廳\',\'C.甜點\':\'甜點\',\'D.咖啡廳\':\'咖啡廳\',\n  \'E.火鍋類\':\'火鍋\',\'F.燒肉\':\'燒肉\',\'G.牛排\':\'牛排\',\'H.鐵板燒\':\'鐵板燒\',\n  \'I.早午餐\':\'早午餐\',\'J.麵包西餅店\':\'麵包甜點\',\'K.海鮮\':\'海鮮\',\n  \'L.中式糕餅\':\'中式糕餅\',\'M.飲料\':\'飲料\',\'N.炸物\':\'炸物\',\'O.冰品\':\'冰品\',\n  \'P.日式\':\'日式\',\'Q.韓式\':\'韓式\',\'R.義式\':\'義式\',\'S.泰式\':\'泰式\',\n  \'T.港式\':\'港式\',\'U.伴手禮\':\'伴手禮\',\'V.餐酒館\':\'餐酒館\',\'W.居酒屋\':\'居酒屋\',\n  \'X.早餐\':\'早餐\',\'Y.喜餅/彌月\':\'喜餅彌月\',\'Z.素食\':\'素食\',\'Z1.酒吧\':\'酒吧\',\'Z2.其他\':\'其他\'\n};\nconst CAT_KEYS=Object.keys(CAT);\nconst CAT_LABELS=Object.values(CAT);\nconst CAT_REV={};Object.entries(CAT).forEach(([k,v])=>CAT_REV[v]=k);\n\n// ===== INDICES =====\n// District lookup: {city+\':\'+dist -> {f:[],h:[],s:[]}}\nconst DIST_IDX={};\nfunction addDistIdx(arr,key){\n  arr.forEach(x=>{\n    const city=nc(x.city||\'\');\n    const dist=x.district||\'\';\n    if(!city||!dist||dist===\'有分店\')return;\n    const k=city+\':\'+dist;\n    if(!DIST_IDX[k])DIST_IDX[k]={f:[],h:[],s:[]};\n    DIST_IDX[k][key].push(x);\n  });\n}\naddDistIdx(F,\'f\');addDistIdx(H,\'h\');addDistIdx(S,\'s\');\n\n// District maps for filter\nfunction buildDistMap(arr){\n  const m={};\n  arr.forEach(x=>{\n    const city=nc((x.city||\'\').split(\',\')[0].trim());\n    const dist=x.district;\n    if(!city||!dist||dist===\'有分店\')return;\n    if(!m[city])m[city]={};\n    if(!m[city][dist])m[city][dist]=0;\n    m[city][dist]++;\n  });\n  return m;\n}\nconst FDIST=buildDistMap(F),HDIST=buildDistMap(H),SDIST=buildDistMap(S);\n\n// ===== STATE =====\nlet curPg=0;\nconst PGS=[\'pg0\',\'pg1\',\'pg2\',\'pg3\',\'pg4\'];\nconst ST={\n  q:{loc:\'\',topic:\'\'},\n  f:{city:\'\',dist:\'\',cat:\'\'},\n  h:{city:\'\',dist:\'\'},\n  s:{city:\'\',dist:\'\'},\n};\nconst INITED={q:0,f:0,h:0,s:0};\nlet isDark=0;\n\n// Rendered arrays (for jump)\nconst REND={f:[],h:[],s:[]};\n\n// ===== NAV =====\nfunction goPage(i){\n  const prev=curPg; curPg=i;\n  PGS.forEach((id,j)=>{\n    const el=document.getElementById(id);\n    el.className=\'pg \'+(j===i?\'on\':j<i?\'hl\':\'hr\');\n  });\n  document.querySelectorAll(\'.np\').forEach(p=>p.classList.toggle(\'on\',+p.dataset.p===i));\n  // Clear filters of page we\'re leaving\n  if(prev!==i){\n    const pkeys=[,\'q\',\'f\',\'h\',\'s\'];\n    const pk=pkeys[prev];\n    if(pk&&pk!==\'q\'){clearFilters(pk,false);}\n  }\n  const keys=[,\'q\',\'f\',\'h\',\'s\'];\n  const k=keys[i];\n  if(k&&!INITED[k]){INITED[k]=1;window[\'init_\'+k]();}\n}\n\nfunction clearFilters(type,refilter=true){\n  const s=ST[type];\n  Object.keys(s).forEach(k=>s[k]=\'\');\n  if(refilter){\n    if(type===\'f\'){rebuildFoodSub();filterF();}\n    else if(type===\'h\'){rebuildHotelSub();filterH();}\n    else if(type===\'s\'){rebuildSpotSub();filterS();}\n    else if(type===\'q\'){filterQ();}\n    // Refresh filter UI\n    [\'city\',\'dist\',\'cat\',\'loc\',\'topic\'].forEach(k=>{\n      const col=document.getElementById(\'fc-\'+type+\'-\'+k);\n      if(col)col.querySelectorAll(\'.ch\').forEach(c=>c.classList.remove(\'on\'));\n      const tog=document.getElementById(\'ft-\'+type+\'-\'+k);\n      if(tog){const lbl=tog.querySelector(\'.fal\');if(lbl)lbl.remove();}\n    });\n  }\n}\n\n// Swipe\nlet tx=0,ty=0;\ndocument.getElementById(\'pgs\').addEventListener(\'touchstart\',e=>{tx=e.touches[0].clientX;ty=e.touches[0].clientY},{passive:true});\ndocument.getElementById(\'pgs\').addEventListener(\'touchend\',e=>{\n  const dx=e.changedTouches[0].clientX-tx,dy=e.changedTouches[0].clientY-ty;\n  if(Math.abs(dx)>65&&Math.abs(dx)>Math.abs(dy)*1.5){\n    if(dx<0&&curPg<4)goPage(curPg+1);\n    else if(dx>0&&curPg>0)goPage(curPg-1);\n  }\n},{passive:true});\n\n// ===== DARK MODE =====\nfunction toggleDark(){\n  isDark=!isDark;\n  document.body.classList.toggle(\'dark\',isDark);\n  document.getElementById(\'dtog\').textContent=isDark?\'☀️\':\'🌙\';\n}\n\n// ===== SEARCH =====\nfunction onSI(type){\n  const inp=document.getElementById(\'si-\'+type);\n  document.getElementById(\'sc-\'+type).classList.toggle(\'show\',inp.value.length>0);\n  ({q:filterQ,f:filterF,h:filterH,s:filterS})[type]();\n}\nfunction clearSI(type){\n  document.getElementById(\'si-\'+type).value=\'\';\n  document.getElementById(\'sc-\'+type).classList.remove(\'show\');\n  ({q:filterQ,f:filterF,h:filterH,s:filterS})[type]();\n}\n\n// ===== FILTER BUILDER =====\nfunction mkFG(type,key,title,chips,active){\n  const fid=\'ft-\'+type+\'-\'+key;\n  const cid=\'fc-\'+type+\'-\'+key;\n  const al=active?`<span class="fal">${esc(active)}</span>`:\'\';\n  return `<div class="fg">\n    <div class="ftog" id="${fid}" onclick="togF(\'${cid}\',\'${fid}\')">\n      <span class="arr">▶</span><span>${title}</span>\n      <span class="fcnt">(${chips.length})</span>${al}\n    </div>\n    <div id="${cid}" style="display:none">\n      <div class="cw">${chips.map(c=>`<span class="ch${c===active?\' on\':\'\'}" onclick="selCh(\'${type}\',\'${key}\',\'${esc2(c)}\',this)">${esc(c)}</span>`).join(\'\')}</div>\n    </div>\n  </div>`;\n}\nfunction togF(cid,fid){\n  const col=document.getElementById(cid),tog=document.getElementById(fid);\n  const op=col.style.display===\'none\';\n  col.style.display=op?\'block\':\'none\';\n  tog.classList.toggle(\'op\',op);\n}\nfunction selCh(type,key,val,el){\n  const wasOn=el.classList.contains(\'on\');\n  el.closest(\'[id^="fc-"]\').querySelectorAll(\'.ch\').forEach(c=>c.classList.remove(\'on\'));\n  const newVal=wasOn?\'\':val;\n  if(!wasOn)el.classList.add(\'on\');\n  const tog=document.getElementById(\'ft-\'+type+\'-\'+key);\n  if(tog){const old=tog.querySelector(\'.fal\');if(old)old.remove();if(newVal){const s=document.createElement(\'span\');s.className=\'fal\';s.textContent=newVal;tog.appendChild(s);}}\n  ST[type][key]=newVal;\n  if(type===\'f\'){\n    if(key===\'city\'){clearSI(\'f\');ST.f.dist=\'\';rebuildFoodSub();}\n    if(key===\'h\'){clearSI(\'h\');ST.h.dist=\'\';rebuildHotelSub();}\n    filterF();\n  } else if(type===\'h\'){\n    if(key===\'city\'){clearSI(\'h\');ST.h.dist=\'\';rebuildHotelSub();}\n    filterH();\n  } else if(type===\'s\'){\n    if(key===\'city\'){clearSI(\'s\');ST.s.dist=\'\';rebuildSpotSub();}\n    filterS();\n  } else if(type===\'q\') filterQ();\n}\n\nfunction getCities(arr){\n  const s=new Set(arr.map(x=>nc((x.city||\'\').split(\',\')[0].trim())).filter(c=>c&&c!==\'有分店\'));\n  return CITY_ORDER.filter(c=>s.has(c));\n}\n\nfunction clrBtn(type){\n  return `<span class="clr-btn" onclick="clearFilters(\'${type}\')">清除篩選</span>`;\n}\n\n// ===== Q PAGE =====\nfunction init_q(){\n  const locs=[...LOC_TAGS].filter(t=>Q.some(x=>x.tags.includes(t)));\n  const locOrd=CITY_ORDER.filter(c=>locs.includes(c));\n  locs.filter(t=>!locOrd.includes(t)).forEach(t=>locOrd.push(t));\n  const topicSet=new Set();\n  Q.forEach(x=>x.tags.forEach(t=>{if(!LOC_TAGS.has(t))topicSet.add(t)}));\n  const topOrd=[];\n  TOPIC_PRI.forEach(t=>{if(topicSet.has(t))topOrd.push(t)});\n  [...topicSet].filter(t=>!topOrd.includes(t)).sort().forEach(t=>topOrd.push(t));\n  document.getElementById(\'fs-q\').innerHTML=\n    mkFG(\'q\',\'loc\',\'地區\',locOrd,ST.q.loc)+\n    mkFG(\'q\',\'topic\',\'主題\',topOrd,ST.q.topic)+\n    clrBtn(\'q\');\n  filterQ();\n}\nfunction filterQ(){\n  const q=(document.getElementById(\'si-q\')||{value:\'\'}).value.trim().toLowerCase();\n  let arr=Q;\n  if(q)arr=arr.filter(x=>x.q.toLowerCase().includes(q));\n  if(ST.q.loc)arr=arr.filter(x=>x.tags.includes(ST.q.loc));\n  if(ST.q.topic)arr=arr.filter(x=>x.tags.includes(ST.q.topic));\n  document.getElementById(\'rc-q\').textContent=\'共 \'+arr.length+\' 筆問題\';\n  renderQ(arr);\n}\nfunction renderQ(arr){\n  document.getElementById(\'ql\').innerHTML=arr.slice(0,300).map((item,i)=>{\n    const loc=item.tags.filter(t=>LOC_TAGS.has(t));\n    const topic=item.tags.filter(t=>!LOC_TAGS.has(t));\n    const cnts=[];\n    if(item.food_count>0)cnts.push(`<span class="qcb qcf">${item.food_count}家美食</span>`);\n    if(item.hotel_count>0)cnts.push(`<span class="qcb qch">${item.hotel_count}家住宿</span>`);\n    if(item.spot_count>0)cnts.push(`<span class="qcb qcs">${item.spot_count}家景點</span>`);\n    const hotBadge=item.top?`<span class="qhot-badge">🔥 熱門問題</span>`:\'\';\n    const rqHtml=item.rqi&&item.rqi.length?`<div class="rq-sec">\n      <div class="rq-title">🔗 相關問題</div>\n      ${item.rqi.map(ri=>`<div class="rq-item" onclick="jumpToQ(${ri})"><span class="rq-sq"></span><span>${esc(Q[ri].q)}</span></div>`).join(\'\')}\n    </div>`:\'\';\n    return `<div class="qc${item.top?\' hot\':\'\'}">\n      <div class="qt">${item.top?\'<span class="qfire">🔥</span>\':\'<span class="qsq"></span>\'}<span>${esc(item.q)}</span></div>\n      <div class="qr2">\n        ${item.date?`<span class="qdate">${item.date}</span>`:\'\'}\n        ${hotBadge}\n        <div class="qcnts">${cnts.join(\'\')}</div>\n      </div>\n      <div class="qtags">\n        ${loc.map(t=>{const r=CITY_REGION[t]||\'t\';const cls=REGION_TAG_CLASS[r]||\'t\';return`<span class="qtag qtag-${cls}">${t}</span>`}).join(\'\')}\n        ${topic.map(t=>`<span class="qtag qtag-t">${t}</span>`).join(\'\')}\n      </div>\n      ${rqHtml}\n    </div>`;\n  }).join(\'\')||\'<div class="empty">沒有找到相關問題</div>\';\n}\nfunction jumpToQ(idx){\n  goPage(1);\n  clearSI(\'q\');\n  ST.q.loc=\'\';ST.q.topic=\'\';\n  setTimeout(()=>{\n    filterQ();\n    setTimeout(()=>{\n      const cards=document.getElementById(\'ql\').querySelectorAll(\'.qc\');\n      // Find by index in filtered (all) Q\n      // We need to find where Q[idx] appears in rendered list\n      // Since we render up to 300 and sorted, find card whose text matches\n      const target=Q[idx].q;\n      let found=null;\n      document.querySelectorAll(\'#ql .qc\').forEach(card=>{\n        const qt=card.querySelector(\'.qt span:last-child\');\n        if(qt&&qt.textContent===target)found=card;\n      });\n      if(found){\n        found.scrollIntoView({behavior:\'smooth\',block:\'center\'});\n        found.style.boxShadow=\'0 0 0 3px var(--gold)\';\n        setTimeout(()=>found.style.boxShadow=\'\',1500);\n      }\n    },300);\n  },350);\n}\n\n// ===== FOOD =====\nfunction init_f(){\n  const cities=getCities(F);\n  const catSet=new Set(F.map(x=>x.cat).filter(Boolean));\n  const cats=CAT_KEYS.filter(k=>catSet.has(k)).map(k=>CAT[k]);\n  document.getElementById(\'fs-f\').innerHTML=\n    mkFG(\'f\',\'city\',\'縣市\',cities,ST.f.city)+\n    \'<div id="fs-f-sub"></div>\'+\n    mkFG(\'f\',\'cat\',\'美食分類\',cats,ST.f.cat)+\n    clrBtn(\'f\');\n  rebuildFoodSub();filterF();\n}\nfunction rebuildFoodSub(){\n  const city=ST.f.city;\n  const el=document.getElementById(\'fs-f-sub\');\n  if(!el)return;\n  if(!city||!FDIST[city]){el.innerHTML=\'\';return;}\n  const dists=Object.keys(FDIST[city]).sort();\n  el.innerHTML=mkFG(\'f\',\'dist\',city+\'行政區\',dists,ST.f.dist);\n}\nfunction filterF(){\n  const q=(document.getElementById(\'si-f\')||{value:\'\'}).value.trim().toLowerCase();\n  let arr=F;\n  if(q)arr=arr.filter(x=>(x.name||\'\').toLowerCase().includes(q)||(x.review||\'\').toLowerCase().includes(q));\n  if(ST.f.city)arr=arr.filter(x=>nc((x.city||\'\').split(\',\')[0].trim())===ST.f.city);\n  if(ST.f.dist)arr=arr.filter(x=>x.district===ST.f.dist);\n  if(ST.f.cat){const k=CAT_REV[ST.f.cat];if(k)arr=arr.filter(x=>x.cat===k);}\n  // Group by district when only city selected\n  if(ST.f.city&&!ST.f.dist&&!ST.f.cat&&!q){\n    arr=[...arr].sort((a,b)=>(a.district||\'\').localeCompare(b.district||\'\',\'zh\'));\n  }\n  document.getElementById(\'rc-f\').textContent=\'共 \'+arr.length+\' 筆美食\';\n  REND.f=arr;renderItems(\'fl\',arr,\'f\');\n}\n\n// ===== HOTEL =====\nfunction init_h(){\n  const cities=getCities(H);\n  document.getElementById(\'fs-h\').innerHTML=\n    mkFG(\'h\',\'city\',\'縣市\',cities,ST.h.city)+\n    \'<div id="fs-h-sub"></div>\'+\n    clrBtn(\'h\');\n  rebuildHotelSub();filterH();\n}\nfunction rebuildHotelSub(){\n  const city=ST.h.city;\n  const el=document.getElementById(\'fs-h-sub\');\n  if(!el)return;\n  if(!city||!HDIST[city]){el.innerHTML=\'\';return;}\n  const dists=Object.keys(HDIST[city]).sort();\n  el.innerHTML=mkFG(\'h\',\'dist\',city+\'行政區\',dists,ST.h.dist);\n}\nfunction filterH(){\n  const q=(document.getElementById(\'si-h\')||{value:\'\'}).value.trim().toLowerCase();\n  let arr=H;\n  if(q)arr=arr.filter(x=>(x.name||\'\').toLowerCase().includes(q)||(x.review||\'\').toLowerCase().includes(q));\n  if(ST.h.city)arr=arr.filter(x=>nc((x.city||\'\').split(\',\')[0].trim())===ST.h.city);\n  if(ST.h.dist)arr=arr.filter(x=>x.district===ST.h.dist);\n  if(ST.h.city&&!ST.h.dist&&!q){\n    arr=[...arr].sort((a,b)=>(a.district||\'\').localeCompare(b.district||\'\',\'zh\'));\n  }\n  document.getElementById(\'rc-h\').textContent=\'共 \'+arr.length+\' 筆住宿\';\n  REND.h=arr;renderItems(\'hl\',arr,\'h\');\n}\n\n// ===== SPOT =====\nfunction init_s(){\n  const cities=getCities(S);\n  document.getElementById(\'fs-s\').innerHTML=\n    mkFG(\'s\',\'city\',\'縣市\',cities,ST.s.city)+\n    \'<div id="fs-s-sub"></div>\'+\n    clrBtn(\'s\');\n  rebuildSpotSub();filterS();\n}\nfunction rebuildSpotSub(){\n  const city=ST.s.city;\n  const el=document.getElementById(\'fs-s-sub\');\n  if(!el)return;\n  if(!city||!SDIST[city]){el.innerHTML=\'\';return;}\n  const dists=Object.keys(SDIST[city]).sort();\n  el.innerHTML=mkFG(\'s\',\'dist\',city+\'行政區\',dists,ST.s.dist);\n}\nfunction filterS(){\n  const q=(document.getElementById(\'si-s\')||{value:\'\'}).value.trim().toLowerCase();\n  let arr=S;\n  if(q)arr=arr.filter(x=>(x.name||\'\').toLowerCase().includes(q)||(x.review||\'\').toLowerCase().includes(q));\n  if(ST.s.city)arr=arr.filter(x=>nc((x.city||\'\').split(\',\')[0].trim())===ST.s.city);\n  if(ST.s.dist)arr=arr.filter(x=>x.district===ST.s.dist);\n  if(ST.s.city&&!ST.s.dist&&!q){\n    arr=[...arr].sort((a,b)=>(a.district||\'\').localeCompare(b.district||\'\',\'zh\'));\n  }\n  document.getElementById(\'rc-s\').textContent=\'共 \'+arr.length+\' 筆景點\';\n  REND.s=arr;renderItems(\'sl\',arr,\'s\');\n}\n\n// ===== RENDER ITEMS =====\nfunction renderItems(cid,arr,type){\n  const shown=arr.slice(0,150);\n  document.getElementById(cid).innerHTML=shown.map((item,idx)=>{\n    const cardId=type+\'-c-\'+idx;\n    const detId=cardId+\'-d\';\n    const btnId=cardId+\'-b\';\n    const catLabel=item.cat?CAT[item.cat]||item.cat:\'\';\n    const isBranch=item.district===\'有分店\';\n    const cityStr=nc(item.city||\'\');\n    const distStr=isBranch?`${cityStr}皆有分店`:(item.district||\'\');\n    const ref=item.tiji||\'\';\n    // meta: food shows category; hotel/spot shows only ref (not city tag)\n    const metaParts=[];\n    if(type===\'f\'&&catLabel) metaParts.push(`<span class="mcat">${esc(catLabel)}</span>`);\n    if(distStr) metaParts.push(`<span>${esc(distStr)}</span>`);\n    if(ref){\n      // strip leading city tags like "新北 推薦..." -> show only question part\n      const refClean=ref.replace(/^[^\\s]+\\s/,\'\');\n      metaParts.push(`<span class="mref">${esc(ref)}</span>`);\n    }\n    const links=[\n      item.google?`<a class="lnk lnk-g" href="${item.google}" target="_blank">📍 Google Maps</a>`:\'\',\n      item.fb?`<a class="lnk lnk-f" href="${item.fb}" target="_blank">FB</a>`:\'\',\n      item.ig?`<a class="lnk lnk-i" href="${item.ig}" target="_blank">IG</a>`:\'\',\n      item.website?`<a class="lnk lnk-w" href="${item.website}" target="_blank">官網</a>`:\'\',\n    ].filter(Boolean).join(\'\');\n\n    // Related questions\n    const qiHtml=(item.qi&&item.qi.length)?`<div class="rq-sec">\n      <div class="rq-title">💬 出現在這些問題</div>\n      ${item.qi.map(qi=>`<div class="rq-item" onclick="jumpToQ(${qi})"><span class="rq-sq"></span><span>${esc(Q[qi].q)}</span></div>`).join(\'\')}\n    </div>`:\'\';\n\n    return `<div class="ic" id="${cardId}">\n      <div class="ih" onclick="togDet(\'${detId}\',\'${btnId}\')">\n        <div>\n          <div class="in">${esc(item.name||\'\')}</div>\n          <div class="im">${metaParts.join(\'<span style="color:var(--gray);margin:0 2px">·</span>\')}</div>\n        </div>\n        <div class="ieb" id="${btnId}">▼</div>\n      </div>\n      <div class="idet" id="${detId}">\n        ${item.review?`<div class="rev">${esc(item.review)}</div>`:\'<div class="rev" style="color:var(--gray)">（無心得）</div>\'}\n        ${links?`<div class="lnks">${links}</div>`:\'\'}\n        ${qiHtml}\n        ${buildNearby(item,type)}\n      </div>\n    </div>`;\n  }).join(\'\')||\'<div class="empty">沒有找到相關資料</div>\';\n  if(arr.length>150){\n    document.getElementById(cid).innerHTML+=\'<div class="empty">（顯示前150筆，請用搜尋或篩選縮小範圍）</div>\';\n  }\n}\n\nfunction togDet(did,bid){\n  const el=document.getElementById(did),btn=document.getElementById(bid);\n  const op=el.classList.toggle(\'op\');\n  if(btn)btn.textContent=op?\'▲\':\'▼\';\n}\n\n// ===== NEARBY =====\nfunction buildNearby(item,type){\n  const city=nc((item.city||\'\').split(\',\')[0].trim());\n  const dist=item.district;\n  if(!dist||dist===\'有分店\') return \'<div class="nb-sec"><div class="nb-title">📍 附近還有</div><div class="nb-none">【無】</div></div>\';\n  const k=city+\':\'+dist;\n  const idx=DIST_IDX[k]||{f:[],h:[],s:[]};\n  const selfName=item.name;\n  const nf=idx.f.filter(x=>x.name!==selfName);\n  const nh=idx.h.filter(x=>x.name!==selfName);\n  const ns=idx.s.filter(x=>x.name!==selfName);\n  const total=nf.length+nh.length+ns.length;\n  if(!total) return `<div class="nb-sec"><div class="nb-title">📍 ${dist}還有</div><div class="nb-none">【無】</div></div>`;\n\n  const LIMIT=5;\n  function mkGroup(label,arr,ntype,pg){\n    if(!arr.length)return\'\';\n    const shown=arr.slice(0,LIMIT);\n    const extra=arr.slice(LIMIT);\n    const eid=\'nb-\'+selfName.replace(/[^a-z0-9]/gi,\'_\')+ntype;\n    return `<div class="nb-gtitle">${label}（${arr.length}家）</div>\n      ${shown.map(x=>`<div class="nb-item" onclick="jumpToItem(\'${esc2(x.name)}\',\'${ntype}\',${pg})">▸ <span>${esc(x.name)}</span>${x.cat?`<span style="color:var(--gray);font-size:10px;margin-left:4px">${CAT[x.cat]||\'\'}</span>`:\'\'}</div>`).join(\'\')}\n      ${extra.length?`<div class="nb-extra" id="${eid}">${extra.map(x=>`<div class="nb-item" onclick="jumpToItem(\'${esc2(x.name)}\',\'${ntype}\',${pg})">▸ <span>${esc(x.name)}</span></div>`).join(\'\')}</div>\n      <div class="nb-more" onclick="togNbExtra(\'${eid}\',this)">▶ 顯示更多 ${extra.length} 家</div>`:\'\'}`;\n  }\n  return `<div class="nb-sec">\n    <div class="nb-title">📍 ${dist}還有</div>\n    ${mkGroup(\'美食\',nf,\'f\',2)}\n    ${mkGroup(\'住宿\',nh,\'h\',3)}\n    ${mkGroup(\'景點\',ns,\'s\',4)}\n  </div>`;\n}\n\nfunction togNbExtra(eid,btn){\n  const el=document.getElementById(eid);\n  if(!el)return;\n  const op=el.classList.toggle(\'op\');\n  btn.textContent=op?\'▲ 收起\':\'▶ 顯示更多\';\n}\n\n// ===== JUMP TO ITEM =====\nfunction jumpToItem(name,type,pg){\n  goPage(pg);\n  setTimeout(()=>{\n    // Reset state & filter for type\n    Object.keys(ST[type]).forEach(k=>ST[type][k]=\'\');\n    clearSI(type);\n    if(type===\'f\'){rebuildFoodSub();filterF();}\n    else if(type===\'h\'){rebuildHotelSub();filterH();}\n    else if(type===\'s\'){rebuildSpotSub();filterS();}\n    setTimeout(()=>{\n      const arr=REND[type];\n      const idx=arr.findIndex(x=>x.name===name);\n      if(idx<0)return;\n      const cardId=type+\'-c-\'+idx;\n      const detId=cardId+\'-d\';\n      const btnId=cardId+\'-b\';\n      const card=document.getElementById(cardId);\n      if(!card)return;\n      card.scrollIntoView({behavior:\'smooth\',block:\'center\'});\n      const det=document.getElementById(detId);\n      if(det&&!det.classList.contains(\'op\')){\n        det.classList.add(\'op\');\n        const btn=document.getElementById(btnId);\n        if(btn)btn.textContent=\'▲\';\n      }\n      card.style.boxShadow=\'0 0 0 3px var(--gold)\';\n      setTimeout(()=>card.style.boxShadow=\'\',1500);\n    },350);\n  },320);\n}\n\n// ===== HOME =====\nfunction initHome(){\n  document.getElementById(\'hgrid\').innerHTML=[\n    {lbl:\'問題\',cnt:Q.length,pg:1,ico:\'🔍\'},\n    {lbl:\'美食\',cnt:F.length,pg:2,ico:\'🍽️\'},\n    {lbl:\'住宿\',cnt:H.length,pg:3,ico:\'🏨\'},\n    {lbl:\'景點\',cnt:S.length,pg:4,ico:\'🗺️\'},\n  ].map(x=>`<div class="hcard" onclick="goPage(${x.pg})">\n    <div class="hico">${x.ico}</div>\n    <div class="hlbl">${x.lbl}</div>\n    <div class="hnum">${x.cnt.toLocaleString()}</div>\n  </div>`).join(\'\');\n}\n\n// ===== BACK TO TOP =====\nfunction backTop(pgId){\n  const el=document.getElementById(pgId);\n  if(el)el.scrollTop=0;\n}\n\n// ===== UTILS =====\nfunction esc(s){\n  if(!s)return\'\';\n  return String(s).replace(/&/g,\'&amp;\').replace(/</g,\'&lt;\').replace(/>/g,\'&gt;\').replace(/"/g,\'&quot;\');\n}\nfunction esc2(s){\n  if(!s)return\'\';\n  return String(s).replace(/\\\\/g,\'\\\\\\\\\').replace(/\'/g,"\\\\\'");\n}\n\ninitHome();\n</script>\n</body>\n</html>'
